// localStorage keys + grid size — moved here from CornerEditor.js when that
// scene was retired. The renderer still needs to read user-painted overrides
// (legacy users who previously customised their corner pattern), so the
// loader stays. Grid is fixed at 32x32 (CornerEditor sliced 32 cells per side).
const GRID_SIZE       = 32
const NUM_SLOTS       = 4
const LEGACY_KEY      = 'questFailed.cornerPattern'
const SLOT_KEY_PREFIX = 'questFailed.cornerPattern.slot'
const ACTIVE_KEY      = 'questFailed.cornerPattern.activeSlot'

// Read the active corner pattern. Tries the active slot, then the legacy
// single-pattern key, then falls back to DEFAULT_PATTERN. Returns null only
// when DEFAULT_PATTERN is itself null (i.e., game ships with no bundled
// pattern and no user override exists).
export function loadCornerPattern() {
  try {
    const v = localStorage.getItem(ACTIVE_KEY)
    const n = parseInt(v, 10)
    const slot = (n >= 1 && n <= NUM_SLOTS) ? n : 1
    const raw = localStorage.getItem(SLOT_KEY_PREFIX + slot)
    if (raw) {
      const data = JSON.parse(raw)
      if (Array.isArray(data) && data.length === GRID_SIZE) return data
    }
    const legacy = localStorage.getItem(LEGACY_KEY)
    if (legacy) {
      const data = JSON.parse(legacy)
      if (Array.isArray(data) && data.length === GRID_SIZE) return data
    }
  } catch (e) {}
  if (Array.isArray(DEFAULT_PATTERN) && DEFAULT_PATTERN.length === GRID_SIZE) {
    return DEFAULT_PATTERN
  }
  return null
}
